import{_ as t,o,c as a,a2 as i}from"./chunks/framework.DGp-bpT-.js";const m=JSON.parse('{"title":"Communicating with the Bot and Interaction Rules","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/interaction.md","filePath":"en/guide/interaction.md","lastUpdated":1779266159000}'),n={name:"en/guide/interaction.md"};function s(l,e,r,c,u,d){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="communicating-with-the-bot-and-interaction-rules" tabindex="-1">Communicating with the Bot and Interaction Rules <a class="header-anchor" href="#communicating-with-the-bot-and-interaction-rules" aria-label="Permalink to &quot;Communicating with the Bot and Interaction Rules&quot;">​</a></h1><p>The SREBot platform allows you not only to receive automatic alert analysis (RCA) but also to dialogue with the bot in chat to clarify details.</p><h2 id="how-to-ask-a-follow-up-question" tabindex="-1">How to Ask a Follow-up Question <a class="header-anchor" href="#how-to-ask-a-follow-up-question" aria-label="Permalink to &quot;How to Ask a Follow-up Question&quot;">​</a></h2><p>To ask the bot a question about a specific incident:</p><ol><li>Find the bot&#39;s message with the analysis (RCA) in the Telegram channel or chat.</li><li>Reply to this message (<strong>Reply</strong>) with your question.</li><li>The bot will see your reply, show an &quot;Analyzing...&quot; status, and send the clarified information.</li></ol><h2 id="rules-for-interacting-with-the-bot" tabindex="-1">Rules for Interacting with the Bot <a class="header-anchor" href="#rules-for-interacting-with-the-bot" aria-label="Permalink to &quot;Rules for Interacting with the Bot&quot;">​</a></h2><p>To ensure the bot works efficiently and does not waste your tokens, please follow these rules:</p><h3 id="_1-topic-of-questions" tabindex="-1">1. Topic of Questions <a class="header-anchor" href="#_1-topic-of-questions" aria-label="Permalink to &quot;1. Topic of Questions&quot;">​</a></h3><p>The bot is designed as a professional SRE assistant. It responds <strong>only to questions related to the current incident</strong>, the provided analysis, or general diagnostics and observability tasks.</p><p><strong>Examples of good questions:</strong></p><ul><li><em>“Show logs for the last 10 minutes from this node”</em></li><li><em>“What was the CPU usage at the time of the alert?”</em></li><li><em>“What other alerts triggered in this cluster within the hour?”</em></li></ul><p><strong>Off-topic Protection:</strong> If you ask the bot about something unrelated to the incident (e.g., <em>“tell a joke”</em> or <em>“how are you”</em>), the bot will politely refuse to answer to save your organization&#39;s token balance.</p><h3 id="_2-communication-language" tabindex="-1">2. Communication Language <a class="header-anchor" href="#_2-communication-language" aria-label="Permalink to &quot;2. Communication Language&quot;">​</a></h3><p>The bot can communicate in different languages. The response language is configured in the control panel or via the <code>LLM_RESPONSE_LANGUAGE</code> environment variable. If you want the bot to respond in Russian, make sure this parameter is set to <code>Russian</code>.</p><h3 id="_3-constraints-limits" tabindex="-1">3. Constraints (Limits) <a class="header-anchor" href="#_3-constraints-limits" aria-label="Permalink to &quot;3. Constraints (Limits)&quot;">​</a></h3><p>To protect against infinite loops and spam, the following limits apply:</p><ul><li><strong>Cooldown</strong>: there must be a pause between questions from the same user (default is 10 seconds).</li><li><strong>Maximum turns</strong>: a limited number of questions can be asked per incident (default is 5). If the limit is exceeded, the bot will notify you.</li></ul><p>These parameters are configured on the bot side (<code>FOLLOWUP_COOLDOWN</code>, <code>FOLLOWUP_MAX_TURNS</code>).</p><h2 id="management-commands-mute-unmute-status" tabindex="-1">Management Commands (Mute / Unmute / Status) <a class="header-anchor" href="#management-commands-mute-unmute-status" aria-label="Permalink to &quot;Management Commands (Mute / Unmute / Status)&quot;">​</a></h2><p>You can temporarily suspend alert analysis and notifications using management commands. Commands can be sent with or without a slash (<code>/</code>).</p><h3 id="_1-suspend-notifications-mute" tabindex="-1">1. Suspend Notifications (Mute) <a class="header-anchor" href="#_1-suspend-notifications-mute" aria-label="Permalink to &quot;1. Suspend Notifications (Mute)&quot;">​</a></h3><p>The command <code>mute [duration]</code> (or <code>/mute [duration]</code>) activates silence mode.</p><ul><li><strong>Duration format</strong>: supports seconds (<code>s</code>), minutes (<code>m</code>), hours (<code>h</code>), and days (<code>d</code>). For example: <code>30m</code>, <code>2h</code>, <code>1d</code>, <code>1h 30m</code>.</li><li><strong>Default duration</strong>: if no duration is specified, silence mode is activated for <strong>1 hour</strong>.</li></ul><p>It can be applied in two scopes:</p><ul><li><strong>Specific Alert Type (Mute Alert)</strong>: Send the command <code>mute 2h</code> as a <strong>reply</strong> to the bot&#39;s analysis (RCA) message. The bot will silence only this specific alert type (e.g. <code>HighCpuUsage</code>) in the current chat.</li><li><strong>Global Silence (Mute Chat)</strong>: Send the command <code>mute 2h</code> as a regular message in the chat. The bot will temporarily stop analyzing all incoming alerts for this chat.</li></ul><h3 id="_2-resume-notifications-unmute" tabindex="-1">2. Resume Notifications (Unmute) <a class="header-anchor" href="#_2-resume-notifications-unmute" aria-label="Permalink to &quot;2. Resume Notifications (Unmute)&quot;">​</a></h3><p>The command <code>unmute</code> (or <code>/unmute</code>) deactivates silence mode.</p><ul><li><strong>Resume Specific Alert Type</strong>: Send <code>unmute</code> as a <strong>reply</strong> to the bot&#39;s analysis (RCA) message. The bot will resume analysis only for that specific alert type.</li><li><strong>Global Resume</strong>: Send <code>unmute</code> as a regular message in the chat. This will clear all active silences (both global and alert-specific) for the chat.</li></ul><h3 id="_3-check-silence-status-status" tabindex="-1">3. Check Silence Status (Status) <a class="header-anchor" href="#_3-check-silence-status-status" aria-label="Permalink to &quot;3. Check Silence Status (Status)&quot;">​</a></h3><p>The command <code>status</code> (or <code>/status</code>) lists all active silence rules in the current chat, showing the remaining duration for each.</p><ul><li>If there are no active silences, the bot will respond confirming that it is running normally.</li></ul><h3 id="_4-targeting-specific-bots-multi-bot-chats" tabindex="-1">4. Targeting Specific Bots (Multi-bot Chats) <a class="header-anchor" href="#_4-targeting-specific-bots-multi-bot-chats" aria-label="Permalink to &quot;4. Targeting Specific Bots (Multi-bot Chats)&quot;">​</a></h3><p>If you have multiple bots in the same group chat, you can target commands to a specific bot instance by appending its username suffix:</p><ul><li><code>/mute@SreBotA 30m</code> — silences only <code>@SreBotA</code>.</li><li><code>/status@SreBotB</code> — queries status only from <code>@SreBotB</code>.</li></ul><p>If no username suffix is provided, the command will be processed by all bots that can read chat messages.</p>',35)])])}const p=t(n,[["render",s]]);export{m as __pageData,p as default};
